// auth/loadUser.ts
export async function loadUser(req, res, next) {
  try {
    const id = req.session?.userId;
    if (!id) return next(err401());

    const user = await db.findUser(id); // preserve single error-mapping site via catch → next(err)
    if (!user) return next(err404());

    audit.log("user.load", { id });
    cache.set(`user:${id}`, user);

    req.user = user;
    return next();
  } catch (err) {
    return next(err); // db.findUser failure path
  }
}
```

Invariants:
- order: `missing_id → db.findUser → not_found → audit.log → cache.set`
- identity from `session.userId` only (no `x-user-id` trust)
- single error mapping: all failures flow through `next(err)`
- `async`/`await` preserves execution order; no callback signature change

Verification:
- missing session → `401` via `next(err401())`, no db call
- `db.findUser` rejects → `next(err)` once, no audit/cache side effects
- user not found → `next(err404())`, no audit/cache writes
- happy path → audit.log then cache.set then `next()` exactly once
- no duplicate `next` invocation on any branch

Risks:
- `!` `db.findUser` previously callback-style: confirm it returns a Promise or wrap with `promisify`; `this`-binding may break if method is unbound
- `?` audit.log / cache.set sync vs async: if async, decide fire-and-forget vs `await` (current patch is fire-and-forget, matches legacy semantics)

